import sailpoint.object.*;
import sailpoint.api.*;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.tools.Util;
import sailpoint.tools.GeneralException;
import sailpoint.object.Filter;

Filter filter=Filter.or(Filter.eq("name",selectedIdentityId),Filter.eq("id",selectedIdentityId));

Identity identity = context.getUniqueObject(Identity.class, filter);
identityName = identity.getName();

ProvisioningPlan plan = new ProvisioningPlan();
plan.setIdentity(identity);
AccountRequest acctReq = new AccountRequest(AccountRequest.Operation.Create, "ActiveDirectory", null, null);
plan.add(acctReq);

log.error(" plan variable in CreateADProvisioningPlan step...."+plan.toXml());
return plan;

import sailpoint.object.*;
import sailpoint.api.*;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.tools.Util;
import sailpoint.tools.GeneralException;
import java.io.UnsupportedEncodingException;
import java.nio.ByteBuffer;
import java.util.UUID;
import org.apache.commons.codec.DecoderException;
import org.apache.commons.codec.binary.Base64;
import org.apache.commons.codec.binary.Hex;
import sailpoint.object.Link;
import sailpoint.object.Attributes;


// Convert the hex string to Base64
public String getImmutableID(String objectGUID) throws UnsupportedEncodingException{
String immutableID = "";

if(objectGUID.startsWith("{") && objectGUID.endsWith("}")){
immutableID = objectGUID.replace("{", "").replace("}", "");
}
UUID uuidObject = UUID.fromString(immutableID.trim());
byte[] base64EncByte=Base64.encodeBase64(UuidToGuidByteArray(uuidObject));
immutableID = new String(base64EncByte,"UTF-8");

return immutableID;
}


// Convert the bindable string that is obtained from AD to the hex string that can
// be used to convert to Base64
public byte[] UuidToGuidByteArray(UUID uuid)
{
ByteBuffer bytebuffObj = ByteBuffer.wrap(new byte[16]);
bytebuffObj.putLong(uuid.getMostSignificantBits());
bytebuffObj.putLong(uuid.getLeastSignificantBits());


byte[] guidFormatObj = bytebuffObj.array();
byte swap;


swap = guidFormatObj[0];
guidFormatObj[0] = guidFormatObj[3];
guidFormatObj[3] = swap;
swap = guidFormatObj[1];
guidFormatObj[1] = guidFormatObj[2];
guidFormatObj[2] = swap;
swap = guidFormatObj[4];
guidFormatObj[4] = guidFormatObj[5];
guidFormatObj[5] = swap;
swap = guidFormatObj[6];
guidFormatObj[6] = guidFormatObj[7];
guidFormatObj[7] = swap;


return guidFormatObj;
}


Filter filter=Filter.or(Filter.eq("name",selectedIdentityId),Filter.eq("id",selectedIdentityId));
Identity identity = context.getUniqueObject(Identity.class, filter);


List linkList = identity.getLinks();
Link acmeADlink = null;
for (int i=0; i<linkList.size();i++){
acmeADlink = (Link)linkList.get(i);
if (acmeADlink.getApplicationName().trim().equalsIgnoreCase("ActiveDirectory")){
break; 
}
}

String objectguid = acmeADlink.getAttributes().getString("objectguid");
String immutableID = getImmutableID(objectguid);

identityName = identity.getName();

ProvisioningPlan plan = new ProvisioningPlan();
plan.setIdentity(identity);
AccountRequest acctReq = new AccountRequest(AccountRequest.Operation.Create, "Azure Active Directory", null, null);
AttributeRequest attributeRequest = new AttributeRequest("immutableId",ProvisioningPlan.Operation.Add,immutableID);
acctReq.add(attributeRequest);
plan.add(acctReq);

log.error(" plan variable in CreateAzureProvisioningPlan step...."+plan.toXml());

return plan;
